import{_ as t,o,c as r,i as s}from"./chunks/framework.2KsE0g5C.js";const g=JSON.parse('{"title":"Developer Resources","description":"","frontmatter":{},"headers":[],"relativePath":"resources/developers.md","filePath":"resources/developers.md"}'),a={name:"resources/developers.md"};function n(i,e,l,d,c,h){return o(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="developer-resources" tabindex="-1">Developer Resources <a class="header-anchor" href="#developer-resources" aria-label="Permalink to &quot;Developer Resources&quot;">​</a></h1><p>Helpful links, tools, and references for developers working with the Cobalt Design System.</p><blockquote><p><strong>Note:</strong> This page is a living document. Content will be expanded as new tools and guides become available.</p></blockquote><h2 id="package-registry" tabindex="-1">Package Registry <a class="header-anchor" href="#package-registry" aria-label="Permalink to &quot;Package Registry&quot;">​</a></h2><ul><li><strong>npm:</strong> All Cobalt packages are published under the <code>@cobalt</code> scope</li><li><strong>Versions:</strong> Check the <a href="/cobalt-design-system/release-notes.html">Release Notes</a> for the latest release information</li><li><strong>Compatibility:</strong> See the <a href="/cobalt-design-system/getting-started/developers.html">Getting Started for Developers</a> guide for supported frameworks and versions</li></ul><h2 id="browser-devtools-tips" tabindex="-1">Browser DevTools Tips <a class="header-anchor" href="#browser-devtools-tips" aria-label="Permalink to &quot;Browser DevTools Tips&quot;">​</a></h2><ul><li>Use the <strong>Elements</strong> panel to inspect Shadow DOM inside <code>&lt;co-*&gt;</code> components — expand the <code>#shadow-root</code> node to see internal structure</li><li>The <strong>Styles</strong> pane shows CSS custom properties inherited by components — search for <code>--co-</code> to find active tokens</li><li>Use <strong>Computed</strong> tab to see resolved token values when debugging theming issues</li></ul><h2 id="recommended-vs-code-extensions" tabindex="-1">Recommended VS Code Extensions <a class="header-anchor" href="#recommended-vs-code-extensions" aria-label="Permalink to &quot;Recommended VS Code Extensions&quot;">​</a></h2><ul><li><strong>Lit Plugin</strong> — Syntax highlighting, type-checking, and completions for Lit templates</li><li><strong>Custom Elements Manifest Analyzer</strong> — IntelliSense for custom element tags and attributes</li><li><strong>CSS Variable Autocomplete</strong> — Autocomplete for <code>--co-*</code> token names in stylesheets</li></ul><h2 id="related-technologies" tabindex="-1">Related Technologies <a class="header-anchor" href="#related-technologies" aria-label="Permalink to &quot;Related Technologies&quot;">​</a></h2><p>Cobalt builds on top of these open-source projects:</p><table tabindex="0"><thead><tr><th>Technology</th><th>Role in Cobalt</th><th>Documentation</th></tr></thead><tbody><tr><td>Lit</td><td>Web component framework</td><td><a href="https://lit.dev" target="_blank" rel="noreferrer">lit.dev</a></td></tr><tr><td>Lion</td><td>Base component library</td><td><a href="https://lion.js.org" target="_blank" rel="noreferrer">lion.js.org</a></td></tr><tr><td>Style Dictionary</td><td>Token build pipeline</td><td><a href="https://styledictionary.com" target="_blank" rel="noreferrer">styledictionary.com</a></td></tr><tr><td>VitePress</td><td>Documentation site</td><td><a href="https://vitepress.dev" target="_blank" rel="noreferrer">vitepress.dev</a></td></tr></tbody></table><h2 id="troubleshooting-quick-reference" tabindex="-1">Troubleshooting Quick Reference <a class="header-anchor" href="#troubleshooting-quick-reference" aria-label="Permalink to &quot;Troubleshooting Quick Reference&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Symptom</th><th>Try This</th></tr></thead><tbody><tr><td>Component not rendering</td><td>Confirm the import is correct and the custom element is registered</td></tr><tr><td>Tokens not applying</td><td>Check that <code>@cobalt/tokens/css/tokens.css</code> is imported before component styles</td></tr><tr><td>Dark mode not working</td><td>Verify <code>data-mode=&quot;dark&quot;</code> is set on the <code>&lt;html&gt;</code> element via <code>setTheme</code></td></tr><tr><td>Styles leaking or overridden</td><td>Review the <a href="/cobalt-design-system/foundations/css-layers.html">CSS Layers</a> guide for cascade order</td></tr><tr><td>Tests failing in CI</td><td>Run <code>pnpm exec playwright install</code> to install browser binaries</td></tr></tbody></table><h2 id="need-help" tabindex="-1">Need Help? <a class="header-anchor" href="#need-help" aria-label="Permalink to &quot;Need Help?&quot;">​</a></h2><p>Visit the <a href="/cobalt-design-system/resources/contact.html">Contact</a> page for all support channels, including GitHub Discussions.</p>',16)])])}const u=t(a,[["render",n]]);export{g as __pageData,u as default};
